  ('f7d17257-042d-4a7d-b09a-1fc0b22ec1a4'::uuid, '3d3772b1-9043-4785-a37c-68c0928527ae'::uuid, null, 'product_updated', 'manufacturer_scraper_auto_review', '{"id":"3d3772b1-9043-4785-a37c-68c0928527ae","title":"DHC Diet Kit Compatible Supplement 30","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Diet Kit Compatible Supplement 30","title_th":"ดีเอชซี อาหารเสริมรองรับชุดตรวจคิทควบคุมน้ำหนัก 30","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dw3ded0ddc/large/32710/32710_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:21.818053+00:00","source_url":"https://www.dhc.co.jp/goods/32710.html","updated_at":"2026-05-21T10:14:21.833563+00:00","admin_notes":null,"description":"体質にあわせたオーダーメイド感覚のサプリメント","product_url":"https://www.dhc.co.jp/goods/32710.html","label_status":"parsed","price_amount":null,"product_kind":"multi","description_en":"Personalized daily supplement pack formulated for specific body types identified via genetic diet testing.","description_th":"อาหารเสริมรายวันแบบปรับตามบุคคล สำหรับประเภทร่างกายที่ระบุจากผลตรวจยีนควบคุมอาหาร","normalized_url":"https://www.dhc.co.jp/goods/32710.html","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Diet Kit Compatible Supplement 30","titleTh":"ดีเอชซี อาหารเสริมรองรับชุดตรวจคิทควบคุมน้ำหนัก 30","htmlHash":"b305b498d34ce8de934e863022b73aba0c3de976facd7b795e5f00cd65794dc2","nutrition":"「DHCダイエット対策キット対応型サプリ（1）～（54）」は、「DHCの遺伝子検査 ダイエット対策キット」の検査結果からわかる体質に対応した、全54パターンのサプリメントです。 体質別のおすすめ成分をバランスよくとることができます。 検査でわかる体質別に全54パターン！ 「DHCの遺伝子検査 ダイエット対策キット」の結果は、性別と遺伝子型の組み合わせから、りんご型と洋なし型でそれぞれ24パターン、バナナ型で4パターン、アダム・イヴ型で2パターンの全54パターンに体質を細分化することができます。「DHCダイエット対策キット対応型サプリ」は、それぞれの体質にきめ細かく対応した、オーダーメイド感覚のサプリメントです。 